// A customer's full name stored as a String
String fullName = "Maria Lopez";
// length() returns the number of characters (spaces count)
int nameLength = fullName.length();
// toUpperCase() converts all letters to uppercase
String upperName = fullName.toUpperCase();
// charAt(0) gets the first character (index 0)
char firstLetter = fullName.charAt(0);
// Check if the name contains a space character
boolean hasSpace = fullName.contains(" ");
System.out.println("Length: " + nameLength);
System.out.println("Uppercase: " + upperName);
System.out.println("First letter: " + firstLetter);
// Expected output:
// Length: 11
// Uppercase: MARIA LOPEZ
// First letter: M
